"""Core definitions for the StreamHub library."""
import uuid


class StreamError(Exception):
    """Base exception for streaming operations."""

    def __init__(self, message, code=None):
        super().__init__(message)
        self.code = code


def create_stream(name, capacity=100):
    """Create a new stream channel."""
    if not name:
        raise StreamError("Stream name is required", code="INVALID")
    return {"id": str(uuid.uuid4())[:8], "name": name, "capacity": capacity, "items": []}

seed_files.streamhub/producer.py:
"""Stream producer for publishing data."""
from .core import StreamError, create_stream


class Producer:
    """Publishes records to a stream channel."""

    def __init__(self, name):
        self.name = name
        self._channel = create_stream(f"prod-{name}")
        self._count = 0

    def send(self, record):
        if record is None:
            raise StreamError(f"Producer '{self.name}': record cannot be None")
        self._count += 1
        return {"seq": self._count, "record": record}

    def stats(self):
        return {"name": self.name, "sent": self._count}

seed_files.streamhub/consumer.py:
"""Stream consumer for reading data."""
from .core import StreamError, create_stream


class Consumer:
    """Reads records from a stream channel."""

    def __init__(self, name, group=None):
        self.name = name
        self.group = group
        self._channel = create_stream(f"cons-{name}")
        self._offset = 0

    def poll(self, count=1):
        if count <= 0:
            raise StreamError(f"Consumer '{self.name}': count must be positive")
        self._offset += count
        return {"offset": self._offset, "records": []}

    def commit(self):
        return self._offset

seed_files.streamhub/transformer.py:
"""Data transformation stage."""
from .core import StreamError


class Transformer:
    """Applies transformations to streaming records."""

    def __init__(self, name="default"):
        self.name = name
        self._ops = []

    def add(self, func, label="op"):
        self._ops.append({"func": func, "label": label})

    def apply(self, record):
        result = record
        for op in self._ops:
            try:
                result = op["func"](result)
            except Exception as e:
                raise StreamError(f"Transform '{op['label']}' failed: {e}")
        return result

seed_files.streamhub/filter.py:
"""Data filtering stage."""
from .core import StreamError


class DataFilter:
    """Filters streaming records by predicates."""

    def __init__(self):
        self._predicates = []

    def add(self, func, label="filter"):
        self._predicates.append({"func": func, "label": label})

    def apply(self, records):
        result = []
        for rec in records:
            try:
                if all(p["func"](rec) for p in self._predicates):
                    result.append(rec)
            except Exception as e:
                raise StreamError(f"Filter failed: {e}")
        return result

seed_files.streamhub/aggregator.py:
"""Data aggregation stage."""
from .core import StreamError, create_stream


class Aggregator:
    """Aggregates streaming records into windows."""

    def __init__(self, window_size=10):
        self.window_size = window_size
        self._buffer = create_stream("aggregator-buf")
        self._windows = []

    def add(self, record):
        if record is None:
            raise StreamError("Cannot aggregate None record")
        self._windows.append(record)
        return len(self._windows)

    def flush(self):
        result = list(self._windows)
        self._windows.clear()
        return result

seed_files.streamhub/router.py:
"""Stream routing for topic-based delivery."""
from .core import StreamError, create_stream


class Router:
    """Routes records to handlers by topic."""

    def __init__(self):
        self._routes = {}
        self._dead_letter = create_stream("dead-letter")

    def add_route(self, topic, handler):
        self._routes[topic] = handler

    def dispatch(self, topic, record):
        handler = self._routes.get(topic)
        if handler is None:
            raise StreamError(f"No route for topic '{topic}'", code="NO_ROUTE")
        return handler(record)

seed_files.streamhub/dispatcher.py:
"""Event dispatcher for stream processing."""
from .core import StreamError, create_stream


class Dispatcher:
    """Dispatches events to registered listeners."""

    def __init__(self):
        self._listeners = {}
        self._queue = create_stream("dispatch-queue")

    def on(self, event, callback):
        if event not in self._listeners:
            self._listeners[event] = []
        self._listeners[event].append(callback)

    def emit(self, event, data=None):
        handlers = self._listeners.get(event, [])
        if not handlers:
            raise StreamError(f"No listeners for event '{event}'")
        results = []
        for h in handlers:
            results.append(h(data))
        return results

seed_files.streamhub/scheduler.py:
"""Task scheduling for periodic stream operations."""
from .core import StreamError


class Scheduler:
    """Schedules periodic processing tasks."""

    def __init__(self):
        self._tasks = {}

    def register(self, name, func, interval=60):
        self._tasks[name] = {"func": func, "interval": interval}

    def run(self, name):
        if name not in self._tasks:
            raise StreamError(f"Unknown task: {name}", code="NOT_FOUND")
        return self._tasks[name]["func"]()

    def list_tasks(self):
        return list(self._tasks.keys())

seed_files.streamhub/buffer.py:
"""Ring buffer for stream backpressure."""
from .core import StreamError, create_stream


class RingBuffer:
    """Fixed-size ring buffer for flow control."""

    def __init__(self, size=256):
        self.size = size
        self._store = create_stream("ring-buffer")
        self._items = []

    def push(self, item):
        if len(self._items) >= self.size:
            raise StreamError(f"Buffer full ({self.size})")
        self._items.append(item)

    def pop(self):
        if not self._items:
            return None
        return self._items.pop(0)

    def count(self):
        return len(self._items)

seed_files.streamhub/cache.py:
"""Stream caching layer."""
from .core import StreamError, create_stream


class StreamCache:
    """Caches recent stream records."""

    def __init__(self, max_size=128):
        self._max = max_size
        self._store = create_stream("cache-store")
        self._data = {}

    def get(self, key):
        return self._data.get(key)

    def put(self, key, value):
        if len(self._data) >= self._max:
            oldest = next(iter(self._data))
            del self._data[oldest]
        self._data[key] = value

    def evict(self, key):
        if key not in self._data:
            raise StreamError(f"Cache key not found: {key}", code="NOT_FOUND")
        del self._data[key]

    def stats(self):
        return {"size": len(self._data), "max": self._max}

