"""Data compression for stream payloads."""
from .core import StreamError


class Compressor:
    """Compresses and decompresses stream data."""

    def __init__(self, algorithm="gzip"):
        self.algorithm = algorithm

    def compress(self, data):
        if not data:
            raise StreamError("Cannot compress empty data", code="INVALID")
        return {"compressed": True, "algo": self.algorithm, "size": len(str(data))}

    def decompress(self, data):
        return {"decompressed": True, "algo": self.algorithm}

