"""Stream health monitoring."""
from .core import StreamError


class Monitor:
    """Tracks stream health and error rates."""

    def __init__(self):
        self._errors = []
        self._metrics = {}

    def record_error(self, exc):
        entry = {"type": type(exc).__name__, "msg": str(exc)}
        if isinstance(exc, StreamError):
            entry["code"] = exc.code
        self._errors.append(entry)

    def record_metric(self, name, value):
        if name not in self._metrics:
            self._metrics[name] = []
        self._metrics[name].append(value)

    def error_count(self):
        return len(self._errors)

    def get_metric(self, name):
        return self._metrics.get(name, [])

seed_files.streamhub/logger.py:
"""Logging middleware for stream operations."""
from .core import StreamError


class StreamLogger:
    """Logs stream operations and errors."""

    def __init__(self):
        self._log = []

    def wrap(self, func, label="op"):
        def wrapper(*args, **kwargs):
            entry = {"label": label}
            try:
                result = func(*args, **kwargs)
                entry["status"] = "ok"
                self._log.append(entry)
                return result
            except StreamError as e:
                entry["status"] = "error"
                entry["detail"] = str(e)
                self._log.append(entry)
                raise
        return wrapper

    def entries(self):
        return list(self._log)

seed_files.streamhub/metrics.py:
"""Metrics collection for stream processing."""
from .core import StreamError


class MetricsCollector:
    """Collects throughput and error metrics."""

    def __init__(self):
        self._counters = {}
        self._errors = []

    def increment(self, name, value=1):
        self._counters[name] = self._counters.get(name, 0) + value

    def record_error(self, exc):
        entry = {"type": type(exc).__name__, "msg": str(exc)}
        if isinstance(exc, StreamError):
            entry["code"] = exc.code
        self._errors.append(entry)

    def get_counter(self, name):
        return self._counters.get(name, 0)

    def report(self):
        return {"counters": dict(self._counters), "errors": len(self._errors)}

