"""Serialization for stream records."""
import json
from .core import StreamError, create_stream


class Serializer:
    """Serializes and deserializes stream records."""

    def __init__(self, format="json"):
        self.format = format
        self._store = create_stream("serializer-buf")

    def encode(self, data):
        return json.dumps(data)

    def decode(self, raw):
        try:
            return json.loads(raw)
        except json.JSONDecodeError as e:
            raise StreamError(f"Decode failed: {e}", code="DESERIALIZE")

seed_files.streamhub/validator.py:
"""Data validation for stream records."""
from .core import StreamError


class Validator:
    """Validates records against defined rules."""

    def __init__(self):
        self._rules = {}

    def add_rule(self, field, check, message="invalid"):
        self._rules[field] = {"check": check, "message": message}

    def validate(self, record):
        errors = []
        for field, rule in self._rules.items():
            val = record.get(field)
            if not rule["check"](val):
                errors.append(f"{field}: {rule['message']}")
        if errors:
            raise StreamError("; ".join(errors), code="VALIDATION")
        return True

seed_files.streamhub/config.py:
"""Configuration management for streams."""
from .core import StreamError, create_stream


class Config:
    """Manages stream configuration settings."""

    def __init__(self, defaults=None):
        self._data = defaults or {}
        self._store = create_stream("config-store")

    def get(self, key, default=None):
        return self._data.get(key, default)

    def set(self, key, value):
        self._data[key] = value

    def require(self, key):
        if key not in self._data:
            raise StreamError(f"Missing required config: {key}", code="CONFIG")
        return self._data[key]

    def load(self, data):
        self._data.update(data)

