"""Specialized error types for stream processing."""
from .core import StreamError


class TimeoutError(StreamError):
    """Raised when a stream operation times out."""

    def __init__(self, operation, seconds):
        super().__init__(f"Operation '{operation}' timed out after {seconds}s", code="TIMEOUT")
        self.operation = operation
        self.seconds = seconds


class ConnectionError(StreamError):
    """Raised when a stream connection fails."""

    def __init__(self, target, reason=None):
        msg = f"Cannot connect to '{target}'"
        if reason:
            msg += f": {reason}"
        super().__init__(msg, code="CONN_FAIL")
        self.target = target

